var EmojiFormatter = class {
  /**
   * Generate HTML/Wiki-link for emoji insertion
   */
  static generateEmojiHtml(emoji, settings) {
    const isLocalImage = emoji.originalPath && !emoji.originalPath.startsWith("http://") && !emoji.originalPath.startsWith("https://");
    if (isLocalImage) {
      const localTemplate = settings.customLocalEmojiTemplate || '<img src="{path}" alt="{text}" title="{text}" class="{classes}">';
      return this.applyEmojiTemplate(emoji, localTemplate, settings);
    }
    const remoteTemplate = settings.customEmojiTemplate || '<img src="{url}" alt="{text}" title="{text}" class="{classes}">';
    return this.applyEmojiTemplate(emoji, remoteTemplate, settings);
  }
  /**
   * Apply custom emoji template with variable substitution
   */
  static applyEmojiTemplate(emoji, template, settings) {
    let filename = "", fullfilename = "";
    if (template.includes("{filename}") || template.includes("{fullfilename}")) {
      const sourceForFilename = emoji.originalPath || emoji.url || "";
      fullfilename = sourceForFilename ? sourceForFilename.substring(sourceForFilename.lastIndexOf("/") + 1) : "";
      const dotIndex = fullfilename.lastIndexOf(".");
      filename = dotIndex !== -1 ? fullfilename.substring(0, dotIndex) : fullfilename;
    }
    const baseClass = emoji.type === "image" ? "emoji-image" : "emoji-text";
    const customClasses = settings.customCssClasses ? ` ${settings.customCssClasses}` : "";
    const allClasses = `${baseClass}${customClasses}`;
    const variables = {
      url: emoji.url ? this.sanitizeUrl(emoji.url) : "",
      path: emoji.originalPath ? this.escapeHtml(emoji.originalPath) : "",
      // Local path for vault images
      name: emoji.key,
      text: this.escapeHtml(emoji.text),
      category: this.escapeHtml(emoji.category),
      type: emoji.type,
      classes: allClasses,
      icon: emoji.icon,
      filename,
      fullfilename
    };
    let result = template;
    for (const [key, value] of Object.entries(variables)) {
      result = result.split(`{${key}}`).join(value);
    }
    return result;
  }
  /**
   * Sanitize URL to prevent XSS attacks
   */
  static sanitizeUrl(url) {
    if (url.startsWith("http://") || url.startsWith("https://")) {
      try {
        const parsedUrl = new URL(url);
        if (parsedUrl.protocol === "http:" || parsedUrl.protocol === "https:") {
          return parsedUrl.toString();
        }
      } catch (error) {
        console.warn("Invalid emoji URL:", url);
        return "";
      }
    }
    return url;
  }
  /**
   * Escape HTML characters to prevent XSS
   */
  static escapeHtml(text) {
    return text.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;").replace(/'/g, "&#39;");
  }
};

